select kb.id as id,kb.title as title, kc.name as ctName,csu.real_name as createName,kco.create_time as pubTime,ksw.id as swId,kco.id as collectId,ku.readCount
from kb_collect kco
left join kb_basic kb on kb.id = kco.basic_id
LEFT JOIN castle_sys_user csu on kb.auth = csu.id
LEFT JOIN kb_category kc on kb.category_id = kc.id
left join kb_subject_warehouse ksw on kc.sw_id = ksw.id
left join (select count(1) as readCount,b_id from kb_basic_user where type= 1
group by b_id) ku on kb.id = ku.b_id

	kco.user_id = #{kbBaseShowDto.createUser}
	and kb.auth != #{kbBaseShowDto.createUser}
	and kb.status = 1
	and kco.type = 1
	and kb.is_deleted = 2

		and kb.category_id in (

			#{kcId}

		)


		and kc.sw_id in (

			#{swId}

		)


		and kb.title like concat('%',#{kbBaseShowDto.title},'%')


		and kco.create_time like concat('%',#{kbBaseShowDto.fromTime},'%')


union
