select kv.id as id,kv.title as title, kc.name as ctName,csu.real_name as createName,kco.create_time as pubTime,ksw.id as swId,kco.id as collectId,ku.readCount
from kb_collect kco
left join kb_video kv on kv.id = kco.basic_id
LEFT JOIN castle_sys_user csu on kv.auth = csu.id
LEFT JOIN kb_category kc on kv.category_id = kc.id
left join kb_subject_warehouse ksw on kc.sw_id = ksw.id
left join (select count(1) as readCount,b_id from kb_basic_user where type= 1
group by b_id) ku on kv.id = ku.b_id

	kco.user_id = #{kbBaseShowDto.createUser}
	and kv.auth = #{kbBaseShowDto.createUser}
	and kco.type = 2
	and kv.is_deleted = 2

		and kv.category_id in (

			#{kcId}

		)


		and kc.sw_id in (

			#{swId}

		)


		and kv.title like concat('%',#{kbBaseShowDto.title},'%')


		and kco.create_time like concat('%',#{kbBaseShowDto.fromTime},'%')

) t2
order by t2.pubTime desc

	limit #{map.offset},#{map.rows}

